    private fun ASTNode.isFunctionLiteralWithArrowOnSameLine(
        lbrace: ASTNode,
        rbrace: ASTNode,
    ): Boolean {
        if (!isPartOf(FUNCTION_LITERAL)) {
            return false
        }
        var leaf = lbrace.nextLeaf()
        while (leaf != null && leaf != rbrace) {
            if (leaf.elementType == ARROW) {
                return true
            }
            if (leaf.isWhiteSpaceWithNewline()) {
                return false
            }
            leaf = leaf.nextLeaf()
        }
        return false
    }

